	/**
	 * Common ingestion path for both add and delete operations.
	 *
	 * @param t        target {@code State} (one of the two buffers)
	 * @param st       statement to ingest
	 * @param isDelete {@code false}=live sketch, {@code true}=tomb‑stone sketch
	 */
	private void ingest(State t, Statement st, boolean isDelete) {
		try {
			String s = str(st.getSubject());
			String p = str(st.getPredicate());
			String o = str(st.getObject());
			String c = str(st.getContext());

			int si = hash(s), pi = hash(p), oi = hash(o), ci = hash(c);
			long hs = valueFingerprint(s);
			long hp = valueFingerprint(p);
			long ho = valueFingerprint(o);
			long hc = valueFingerprint(c);
			long sig = quadFingerprint(hs, hp, ho, hc);
			long spKey = pairKey(si, pi);
			long soKey = pairKey(si, oi);
			long scKey = pairKey(si, ci);
			long poKey = pairKey(pi, oi);
			long pcKey = pairKey(pi, ci);
			long ocKey = pairKey(oi, ci);

			/* Select the correct target maps depending on add / delete. */
			var tgtST = isDelete ? t.delSingleTriples : t.singleTriples;
			var tgtS = isDelete ? t.delSingles : t.singles;
			var tgtP = isDelete ? t.delPairs : t.pairs;

			/* single‑component cardinalities (array-backed) */
			updateCell(tgtST.get(Component.S), si, sig, t.k);
			updateCell(tgtST.get(Component.P), pi, sig, t.k);
			updateCell(tgtST.get(Component.O), oi, sig, t.k);
			updateCell(tgtST.get(Component.C), ci, sig, t.k);

			/* complement sets for singles (array-backed second layer) */
			tgtS.get(Component.S).upd(Component.P, si, hp);
			tgtS.get(Component.S).upd(Component.O, si, ho);
			tgtS.get(Component.S).upd(Component.C, si, hc);

			tgtS.get(Component.P).upd(Component.S, pi, hs);
			tgtS.get(Component.P).upd(Component.O, pi, ho);
			tgtS.get(Component.P).upd(Component.C, pi, hc);

			tgtS.get(Component.O).upd(Component.S, oi, hs);
			tgtS.get(Component.O).upd(Component.P, oi, hp);
			tgtS.get(Component.O).upd(Component.C, oi, hc);

			tgtS.get(Component.C).upd(Component.S, ci, hs);
			tgtS.get(Component.C).upd(Component.P, ci, hp);
			tgtS.get(Component.C).upd(Component.O, ci, ho);

			/* pairs (triples + complements) — row-chunked arrays */
			tgtP.get(Pair.SP).upT(spKey, sig);
			tgtP.get(Pair.SP).up1(spKey, ho);
			tgtP.get(Pair.SP).up2(spKey, hc);

			tgtP.get(Pair.SO).upT(soKey, sig);
			tgtP.get(Pair.SO).up1(soKey, hp);
			tgtP.get(Pair.SO).up2(soKey, hc);

			tgtP.get(Pair.SC).upT(scKey, sig);
			tgtP.get(Pair.SC).up1(scKey, hp);
			tgtP.get(Pair.SC).up2(scKey, ho);

			tgtP.get(Pair.PO).upT(poKey, sig);
			tgtP.get(Pair.PO).up1(poKey, hs);
			tgtP.get(Pair.PO).up2(poKey, hc);

			tgtP.get(Pair.PC).upT(pcKey, sig);
			tgtP.get(Pair.PC).up1(pcKey, hs);
			tgtP.get(Pair.PC).up2(pcKey, ho);

			tgtP.get(Pair.OC).upT(ocKey, sig);
			tgtP.get(Pair.OC).up1(ocKey, hs);
			tgtP.get(Pair.OC).up2(ocKey, hp);
		} catch (NullPointerException npe) {
			// ignore NPEs from null values (e.g. missing context)
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Quick cardinalities (public) */
	/* ────────────────────────────────────────────────────────────── */

	public double cardinalitySingle(Component c, String v) {
		State snap = current;
		synchronized (snap) {
			int idx = hash(v);
			AtomicReferenceArray<UpdateSketch> arrAdd = snap.singleTriples.get(c);
			AtomicReferenceArray<UpdateSketch> arrDel = snap.delSingleTriples.get(c);
			UpdateSketch add = arrAdd.get(idx);
			UpdateSketch del = arrDel.get(idx);
			return estimateMinus(add, del);
		}
	}

	public double cardinalityPair(Pair p, String x, String y) {
		State snap = current;
		synchronized (snap) {
			long key = pairKey(hash(x), hash(y));
			UpdateSketch add = snap.pairs.get(p).getTriple(key);
			UpdateSketch del = snap.delPairs.get(p).getTriple(key);
			return estimateMinus(add, del);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Legacy join helpers (unchanged external API) */
	/* ────────────────────────────────────────────────────────────── */

	public double estimateJoinOn(Component join, Pair a, String ax, String ay,
			Pair b, String bx, String by) {
		State snap = current;
		synchronized (snap) {
			return joinPairs(snap, join, a, ax, ay, b, bx, by);
		}
	}

	public double estimateJoinOn(Component j, Component a, String av,
			Component b, String bv) {
		State snap = current;
		synchronized (snap) {
			return joinSingles(snap, j, a, av, b, bv);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* ✦ Fluent BGP builder ✦ */
	/* ────────────────────────────────────────────────────────────── */

	public JoinEstimate estimate(Component joinVar, String s, String p, String o, String c) {
		State snap = current;
		synchronized (snap) {
			PatternStats st = statsOf(snap, joinVar, s, p, o, c);
			Sketch bindings = st.sketch == null ? EMPTY : st.sketch;
			return new JoinEstimate(snap, joinVar, bindings, bindings.getEstimate(), st.card);
		}
	}

	public double estimateCount(Component joinVar, String s, String p, String o, String c) {
		return estimate(joinVar, s, p, o, c).estimate();
	}

	public final class JoinEstimate {
		private final State snap;
		private Component joinVar;
		private Sketch bindings;
		private double distinct;
		private double resultSize;

		private JoinEstimate(State snap, Component joinVar, Sketch bindings,
				double distinct, double size) {
			this.snap = snap;
			this.joinVar = joinVar;
			this.bindings = bindings;
			this.distinct = distinct;
			this.resultSize = size;
		}

		public JoinEstimate join(Component newJoinVar, String s, String p, String o, String c) {
			synchronized (snap) {
				/* stats of the right‑hand relation */
				PatternStats rhs = statsOf(snap, newJoinVar, s, p, o, c);

				/* intersection of bindings */
				Intersection ix = SetOperation.builder().buildIntersection();
				ix.intersect(this.bindings);
				if (rhs.sketch != null) {
					ix.intersect(rhs.sketch);
				}
				Sketch inter = ix.getResult();
				double interDistinct = inter.getEstimate();

				if (interDistinct == 0.0) { // early out
					this.bindings = inter;
					this.distinct = 0.0;
					this.resultSize = 0.0;
					this.joinVar = newJoinVar;
					return this;
				}

				/* average fan‑outs */
				double leftAvg = Math.max(0.001, distinct == 0 ? 0 : resultSize / distinct);
				double rightAvg = Math.max(0.001, rhs.distinct == 0 ? 0 : rhs.card / rhs.distinct);

				/* join‑size estimate */
				double newSize = interDistinct * leftAvg * rightAvg;

				/* round to nearest whole solution count if enabled */
				this.resultSize = roundJoinEstimates ? Math.round(newSize) : newSize;

				/* carry forward */
				this.bindings = inter;
				this.distinct = interDistinct;
				this.joinVar = newJoinVar;
				return this;
			}
		}

		/** Estimated number of solutions produced so far. */
		public double estimate() {
			return resultSize;
		}

		public double size() {
			return resultSize;
		}

		public double count() {
			return resultSize;
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pattern statistics */
	/* ────────────────────────────────────────────────────────────── */

	private static final class PatternStats {
		final Sketch sketch; // Θ‑sketch of join‑var bindings
		final double distinct; // = sketch.getEstimate()
		final double card; // relation size |R|

		PatternStats(Sketch s, double card) {
			this.sketch = s;
			this.distinct = s == null ? 0.0 : s.getEstimate();
			this.card = card;
		}
	}

	/** Build both |R| and Θ‑sketch for one triple pattern. */
	private PatternStats statsOf(State st, Component j,
			String s, String p, String o, String c) {

		Sketch sk = bindingsSketch(st, j, s, p, o, c);

		/* ------------- relation cardinality --------------------------- */
		EnumMap<Component, String> fixed = new EnumMap<>(Component.class);
		if (s != null) {
			fixed.put(Component.S, s);
		}
		if (p != null) {
			fixed.put(Component.P, p);
		}
		if (o != null) {
			fixed.put(Component.O, o);
		}
		if (c != null) {
			fixed.put(Component.C, c);
		}

		double card;

		switch (fixed.size()) {
		case 0:
			card = 0.0;
			break;

		case 1: {
			Map.Entry<Component, String> e = fixed.entrySet().iterator().next();
			card = cardSingle(st, e.getKey(), e.getValue());
			break;
		}

		case 2: {
			Component[] cmp = fixed.keySet().toArray(new Component[0]);
			Pair pr = findPair(cmp[0], cmp[1]);
			if (pr != null) {
				card = cardPair(st, pr, fixed.get(pr.x), fixed.get(pr.y));
			} else { // components not a known pair – conservative min
				double a = cardSingle(st, cmp[0], fixed.get(cmp[0]));
				double b = cardSingle(st, cmp[1], fixed.get(cmp[1]));
				card = Math.min(a, b);
			}
			break;
		}

		default: { // 3 or 4 bound – use smallest single cardinality
			card = Double.POSITIVE_INFINITY;
			for (Map.Entry<Component, String> e : fixed.entrySet()) {
				card = Math.min(card, cardSingle(st, e.getKey(), e.getValue()));
			}
			break;
		}
		}
		return new PatternStats(sk, card);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Snapshot‑level cardinalities */
	/* ────────────────────────────────────────────────────────────── */

	private double cardSingle(State st, Component c, String val) {
		int idx = hash(val);
		UpdateSketch add = st.singleTriples.get(c).get(idx);
		UpdateSketch del = st.delSingleTriples.get(c).get(idx);
		return estimateMinus(add, del);
	}

	private double cardPair(State st, Pair p, String x, String y) {
		long key = pairKey(hash(x), hash(y));
		UpdateSketch add = st.pairs.get(p).getTriple(key);
		UpdateSketch del = st.delPairs.get(p).getTriple(key);
		return estimateMinus(add, del);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Sketch helpers */
	/* ────────────────────────────────────────────────────────────── */

	private Sketch bindingsSketch(State st, Component j,
			String s, String p, String o, String c) {

		EnumMap<Component, String> f = new EnumMap<>(Component.class);
		if (s != null) {
			f.put(Component.S, s);
		}
		if (p != null) {
			f.put(Component.P, p);
		}
		if (o != null) {
			f.put(Component.O, o);
		}
		if (c != null) {
			f.put(Component.C, c);
		}

		if (f.isEmpty()) {
			return null; // no constant – unsupported
		}

		/* 1 constant → single complement */
		if (f.size() == 1) {
			Map.Entry<Component, String> e = f.entrySet().iterator().next();
			return singleWrapper(st, e.getKey()).getComplementSketch(j, hash(e.getValue()));
		}

		/* 2 constants: pair fast path */
		Component[] cs = f.keySet().toArray(new Component[0]);
		if (f.size() == 2) {
			Pair pr = findPair(cs[0], cs[1]);
			if (pr != null && (j == pr.comp1 || j == pr.comp2)) {
				int idxX = hash(f.get(pr.x));
				int idxY = hash(f.get(pr.y));
				return pairWrapper(st, pr).getComplementSketch(j, pairKey(idxX, idxY));
			}
		}

		/* generic fall‑back */
		Sketch acc = null;
		for (Map.Entry<Component, String> e : f.entrySet()) {
			Sketch sk = singleWrapper(st, e.getKey())
					.getComplementSketch(j, hash(e.getValue()));
			if (sk == null) {
				continue;
			}
			if (acc == null) {
				acc = sk;
			} else {
				Intersection ix = SetOperation.builder().buildIntersection();
				ix.intersect(acc);
				ix.intersect(sk);
				acc = ix.getResult();
			}
		}
		return acc;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Pair & single wrappers (read‑only) */
	/* ────────────────────────────────────────────────────────────── */

	private StateSingleWrapper singleWrapper(State st, Component fixed) {
		return new StateSingleWrapper(fixed, st.singles.get(fixed), st.delSingles.get(fixed));
	}

	private StatePairWrapper pairWrapper(State st, Pair p) {
		return new StatePairWrapper(p, st.pairs.get(p), st.delPairs.get(p));
	}

	private static final class StateSingleWrapper {
		final Component fixed;
		final SingleBuild add, del;

		StateSingleWrapper(Component f, SingleBuild add, SingleBuild del) {
			this.fixed = f;
			this.add = add;
			this.del = del;
		}

		Sketch getComplementSketch(Component c, int fi) {
			if (c == fixed) {
				return null;
			}
			AtomicReferenceArray<UpdateSketch> arrA = add.cmpl.get(c);
			AtomicReferenceArray<UpdateSketch> arrD = del.cmpl.get(c);
			if (arrA == null || arrD == null) {
				return null;
			}
			UpdateSketch a = arrA.get(fi);
			UpdateSketch d = arrD.get(fi);
			return subtractSketch(a, d);
		}
	}

	private static final class StatePairWrapper {
		final Pair p;
		final PairBuild add, del;

		StatePairWrapper(Pair p, PairBuild add, PairBuild del) {
			this.p = p;
			this.add = add;
			this.del = del;
		}

		Sketch getComplementSketch(Component c, long key) {
			UpdateSketch a, d;
			if (c == p.comp1) {
				a = add.getComp1(key);
				d = del.getComp1(key);
			} else if (c == p.comp2) {
				a = add.getComp2(key);
				d = del.getComp2(key);
			} else {
				return null;
			}
			return subtractSketch(a, d);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Join primitives */
	/* ────────────────────────────────────────────────────────────── */

	private double joinPairs(State st, Component j,
			Pair a, String ax, String ay,
			Pair b, String bx, String by) {

		long keyA = pairKey(hash(ax), hash(ay));
		long keyB = pairKey(hash(bx), hash(by));

		Sketch sa = pairWrapper(st, a).getComplementSketch(j, keyA);
		Sketch sb = pairWrapper(st, b).getComplementSketch(j, keyB);

		if (sa == null || sb == null) {
			return 0.0;
		}

		Intersection ix = SetOperation.builder().buildIntersection();
		ix.intersect(sa);
		ix.intersect(sb);
		return ix.getResult().getEstimate();
	}

	private double joinSingles(State st, Component j,
			Component a, String av,
			Component b, String bv) {

		int idxA = hash(av), idxB = hash(bv);

		Sketch sa = singleWrapper(st, a).getComplementSketch(j, idxA);
		Sketch sb = singleWrapper(st, b).getComplementSketch(j, idxB);

		if (sa == null || sb == null) {
			return 0.0;
		}

		Intersection ix = SetOperation.builder().buildIntersection();
		ix.intersect(sa);
		ix.intersect(sb);
		return ix.getResult().getEstimate();
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Unified mutable state (add + delete) */
	/* ────────────────────────────────────────────────────────────── */

	private static final class State {
		final int k; // sketch nominal entries
		final int buckets; // array bucket count (outer.nominalEntries)

		/* live (add) sketches */
		final EnumMap<Component, AtomicReferenceArray<UpdateSketch>> singleTriples = new EnumMap<>(
				Component.class);
		final EnumMap<Component, SingleBuild> singles = new EnumMap<>(Component.class);
		final EnumMap<Pair, PairBuild> pairs = new EnumMap<>(Pair.class);

		/* tomb‑stone (delete) sketches */
		final EnumMap<Component, AtomicReferenceArray<UpdateSketch>> delSingleTriples = new EnumMap<>(
				Component.class);
		final EnumMap<Component, SingleBuild> delSingles = new EnumMap<>(Component.class);
		final EnumMap<Pair, PairBuild> delPairs = new EnumMap<>(Pair.class);

		State(int k, int buckets) {
			this.k = k;
			this.buckets = buckets;

			for (Component c : Component.values()) {
				singleTriples.put(c, new AtomicReferenceArray<>(buckets));
				delSingleTriples.put(c, new AtomicReferenceArray<>(buckets));

				singles.put(c, new SingleBuild(k, c, buckets));
				delSingles.put(c, new SingleBuild(k, c, buckets));
			}
			for (Pair p : Pair.values()) {
				pairs.put(p, new PairBuild(k, buckets));
				delPairs.put(p, new PairBuild(k, buckets));
			}
		}

		void clear() {
			singleTriples.values().forEach(SketchBasedJoinEstimator::clearArray);
			delSingleTriples.values().forEach(SketchBasedJoinEstimator::clearArray);

			singles.values().forEach(SingleBuild::clear);
			delSingles.values().forEach(SingleBuild::clear);

			pairs.values().forEach(PairBuild::clear);
			delPairs.values().forEach(PairBuild::clear);
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Build‑time structures */
	/* ────────────────────────────────────────────────────────────── */

	private static final class SingleBuild {
		final int k;
		final int buckets;
		final EnumMap<Component, AtomicReferenceArray<UpdateSketch>> cmpl = new EnumMap<>(Component.class);

		SingleBuild(int k, Component fixed, int buckets) {
			this.k = k;
			this.buckets = buckets;
			for (Component c : Component.values()) {
				if (c != fixed) {
					cmpl.put(c, new AtomicReferenceArray<>(buckets));
				}
			}
		}

		void clear() {
			for (AtomicReferenceArray<UpdateSketch> arr : cmpl.values()) {
				SketchBasedJoinEstimator.clearArray(arr);
			}
		}

		void upd(Component c, int idx, long v) {
			AtomicReferenceArray<UpdateSketch> arr = cmpl.get(c);
			if (arr == null) {
				return;
			}
			UpdateSketch sk = arr.get(idx);
			if (sk == null) {
				sk = newSk(k);
				arr.set(idx, sk);
			}
			sk.update(v);
		}
	}

	private static final class PairBuild {
		final int k;
		final int buckets;

		/** row-chunked: rows indexed by X; each row has AtomicReferenceArray cells over Y */
		final AtomicReferenceArray<Row> rows;

		PairBuild(int k, int buckets) {
			this.k = k;
			this.buckets = buckets;
			this.rows = new AtomicReferenceArray<>(buckets);
		}

		void clear() {
			for (int i = 0; i < buckets; i++) {
				rows.set(i, null);
			}
		}

		void upT(long key, long sig) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			UpdateSketch sk = r.triples.get(y);
			if (sk == null) {
				sk = newSk(k);
				r.triples.set(y, sk);
			}
			sk.update(sig);
		}

		void up1(long key, long v) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			UpdateSketch sk = r.comp1.get(y);
			if (sk == null) {
				sk = newSk(k);
				r.comp1.set(y, sk);
			}
			sk.update(v);
		}

		void up2(long key, long v) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = getOrCreateRow(x);
			UpdateSketch sk = r.comp2.get(y);
			if (sk == null) {
				sk = newSk(k);
				r.comp2.set(y, sk);
			}
			sk.update(v);
		}

		UpdateSketch getTriple(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.triples.get(y);
		}

		UpdateSketch getComp1(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.comp1.get(y);
		}

		UpdateSketch getComp2(long key) {
			int x = (int) (key >>> 32);
			int y = (int) key;
			Row r = rows.get(x);
			return (r == null) ? null : r.comp2.get(y);
		}

		private Row getOrCreateRow(int x) {
			Row r = rows.get(x);
			if (r == null) {
				r = new Row(buckets);
				rows.set(x, r);
			}
			return r;
		}

		static final class Row {
			final AtomicReferenceArray<UpdateSketch> triples;
			final AtomicReferenceArray<UpdateSketch> comp1;
			final AtomicReferenceArray<UpdateSketch> comp2;

			Row(int buckets) {
				this.triples = new AtomicReferenceArray<>(buckets);
				this.comp1 = new AtomicReferenceArray<>(buckets);
				this.comp2 = new AtomicReferenceArray<>(buckets);
			}
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Utility */
	/* ────────────────────────────────────────────────────────────── */

	private static double estimateMinus(UpdateSketch add, UpdateSketch del) {
		if (add == null) {
			return 0.0;
		}
		if (del == null || del.getRetainedEntries() == 0) {
			return add.getEstimate();
		}
		AnotB diff = SetOperation.builder().buildANotB();
		diff.setA(add);
		diff.notB(del);
		return diff.getResult(false).getEstimate();
	}

	private static Sketch subtractSketch(UpdateSketch add, UpdateSketch del) {
		if (add == null) {
			return null;
		}
		if (del == null || del.getRetainedEntries() == 0) {
			return add;
		}
		AnotB diff = SetOperation.builder().buildANotB();
		diff.setA(add);
		diff.notB(del);
		return diff.getResult(false);
	}

	private static UpdateSketch newSk(int k) {
		return UpdateSketch.builder().setNominalEntries(k).build();
	}

	private int hash(String v) {
		// Ensure non-negative index in [0, nominalEntries)
		int h = Objects.hashCode(v);
		return (h & 0x7fffffff) % nominalEntries;
	}

	private static long valueFingerprint(String value) {
		long h = FNV64_OFFSET_BASIS;
		if (value != null) {
			for (int i = 0; i < value.length(); i++) {
				h ^= value.charAt(i);
				h *= FNV64_PRIME;
			}
			h ^= value.length();
		}
		return mix64(h);
	}

	private static long quadFingerprint(long s, long p, long o, long c) {
		long h = QUAD_SEED;
		h = mix64(h ^ s);
		h = mix64(h ^ p);
		h = mix64(h ^ o);
		return mix64(h ^ c);
	}

	private static long mix64(long value) {
		long z = value;
		z = (z ^ (z >>> 30)) * MIX64_C1;
		z = (z ^ (z >>> 27)) * MIX64_C2;
		return z ^ (z >>> 31);
	}

	private static long pairKey(int a, int b) {
		return (((long) a) << 32) ^ (b & 0xffffffffL);
	}

	private static Pair findPair(Component a, Component b) {
		for (Pair p : Pair.values()) {
			if ((p.x == a && p.y == b) || (p.x == b && p.y == a)) {
				return p;
			}
		}
		return null;
	}

	private String str(Resource r) {
		return r == null ? defaultContextString : r.stringValue();
	}

	private String str(Value v) {
		return v == null ? defaultContextString : v.stringValue();
	}

	private static String sig(String s, String p, String o, String c) {
		return s + ' ' + p + ' ' + o + ' ' + c;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* OPTIONAL optimiser helper (unchanged API) */
	/* ────────────────────────────────────────────────────────────── */

	public double cardinality(Join node) {
		if (!isReady()) {
			return -1;
		}

		TupleExpr leftArg = node.getLeftArg();
		TupleExpr rightArg = node.getRightArg();

		if (leftArg instanceof StatementPattern && rightArg instanceof StatementPattern) {
			StatementPattern l = (StatementPattern) leftArg;
			StatementPattern r = (StatementPattern) rightArg;

			/* find first common unbound variable */
			Var common = null;
			List<Var> lVars = l.getVarList();
			for (Var v : r.getVarList()) {
				if (!v.hasValue() && lVars.contains(v)) {
					common = v;
					break;
				}
			}
			if (common == null) {
				return Double.MAX_VALUE; // no common var
			}

			if (!hasBoundComponent(l) || !hasBoundComponent(r)) {
				return -1; // unsupported sketch case, let caller fall back
			}

			Component lc = getComponent(l, common);
			Component rc = getComponent(r, common);

			return this
					.estimate(lc,
							getValueOrNull(l.getSubjectVar()),
							getValueOrNull(l.getPredicateVar()),
							getValueOrNull(l.getObjectVar()),
							getValueOrNull(l.getContextVar()))
					.join(rc,
							getValueOrNull(r.getSubjectVar()),
							getValueOrNull(r.getPredicateVar()),
							getValueOrNull(r.getObjectVar()),
							getValueOrNull(r.getContextVar()))
					.estimate();
		}
		return -1;
	}

	private String getValueOrNull(Var v) {
		return (v == null || v.getValue() == null)
				? null
				: v.getValue().stringValue();
	}

	private boolean hasBoundComponent(StatementPattern sp) {
		return hasBoundValue(sp.getSubjectVar())
				|| hasBoundValue(sp.getPredicateVar())
				|| hasBoundValue(sp.getObjectVar())
				|| hasBoundValue(sp.getContextVar());
	}

	private boolean hasBoundValue(Var var) {
		return var != null && var.hasValue();
	}

	private Component getComponent(StatementPattern sp, Var var) {
		if (var.equals(sp.getSubjectVar())) {
			return Component.S;
		}
		if (var.equals(sp.getPredicateVar())) {
			return Component.P;
		}
		if (var.equals(sp.getObjectVar())) {
			return Component.O;
		}
		if (var.equals(sp.getContextVar())) {
			return Component.C;
		}
		throw new IllegalStateException("Unexpected variable " + var + " in pattern " + sp);
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Staleness API */
	/* ────────────────────────────────────────────────────────────── */

	private static final class ChurnSnapshot {
		final int sampled;
		final int removed;
		final int readded;

		ChurnSnapshot(int sampled, int removed, int readded) {
			this.sampled = sampled;
			this.removed = removed;
			this.readded = readded;
		}

		double removalRatio() {
			return sampled == 0 ? 0.0 : (double) removed / (double) sampled;
		}

		double readdRatio() {
			return sampled == 0 ? 0.0 : (double) readded / (double) sampled;
		}
	}

	private static final class ChurnSampler {
		private enum State {
			ADDED,
			DELETED_AFTER_ADD,
			READDED_AFTER_DELETE
		}

		private final ConcurrentHashMap<String, State> samples = new ConcurrentHashMap<>();
		private long eventsSinceLastSample = 0L;

		void reset() {
			samples.clear();
			eventsSinceLastSample = 0L;
		}

		void recordAdd(String signature, long sampleEvery) {
			record(signature, sampleEvery, true);
		}

		void recordDelete(String signature, long sampleEvery) {
			record(signature, sampleEvery, false);
		}

		private void record(String signature, long sampleEvery, boolean isAdd) {
			if (sampleEvery <= 0) {
				return;
			}
			eventsSinceLastSample++;
			if (eventsSinceLastSample < sampleEvery) {
				return;
			}
			eventsSinceLastSample = 0L;

			samples.compute(signature, (sig, state) -> {
				if (state == null) {
					return isAdd ? State.ADDED : null;
				}
				if (isAdd && state == State.DELETED_AFTER_ADD) {
					return State.READDED_AFTER_DELETE;
				}
				if (!isAdd && state == State.ADDED) {
					return State.DELETED_AFTER_ADD;
				}
				return state;
			});
		}

		ChurnSnapshot snapshot() {
			int sampled = 0;
			int removed = 0;
			int readded = 0;
			for (State state : samples.values()) {
				sampled++;
				if (state == State.DELETED_AFTER_ADD || state == State.READDED_AFTER_DELETE) {
					removed++;
				}
				if (state == State.READDED_AFTER_DELETE) {
					readded++;
				}
			}
			return new ChurnSnapshot(sampled, removed, readded);
		}
	}

	/**
	 * Immutable staleness snapshot. All values are approximate by design.
	 */
	public static final class Staleness {
		public final long ageMillis; // AoI: time since last publish
		public final long lastRebuildPublishMs;

		// churn-specific
		public final int sampledAdds;
		public final int sampledRemoved;
		public final int sampledReadded;
		public final double sampledRemovalRatio;
		public final double sampledReaddRatio;

		public final double stalenessScore; // combined 0..1+

		private Staleness(
				long ageMillis,
				long lastRebuildPublishMs,
				int sampledAdds,
				int sampledRemoved,
				int sampledReadded,
				double sampledRemovalRatio,
				double sampledReaddRatio,
				double stalenessScore) {
			this.ageMillis = ageMillis;
			this.lastRebuildPublishMs = lastRebuildPublishMs;
			this.sampledAdds = sampledAdds;
			this.sampledRemoved = sampledRemoved;
			this.sampledReadded = sampledReadded;
			this.sampledRemovalRatio = sampledRemovalRatio;
			this.sampledReaddRatio = sampledReaddRatio;
			this.stalenessScore = stalenessScore;
		}

		@Override
		public String toString() {
			return "Staleness{" +
					"ageMillis=" + ageMillis +
					", lastRebuildPublishMs=" + lastRebuildPublishMs +
					", sampledAdds=" + sampledAdds +
					", sampledRemoved=" + sampledRemoved +
					", sampledReadded=" + sampledReadded +
					", sampledRemovalRatio=" + sampledRemovalRatio +
					", sampledReaddRatio=" + sampledReaddRatio +
					", stalenessScore=" + stalenessScore +
					'}';
		}
	}

	/**
	 * Compute a staleness snapshot using the *current* published State. No locks taken.
	 *
	 * This is O(total number of populated sketch keys) and intended for occasional diagnostics or adaptive scheduling.
	 * All numbers are approximate by design of Theta sketches.
	 */
	public Staleness staleness() {
		final long now = System.currentTimeMillis();
		final long age = lastRebuildPublishMs == 0L ? Long.MAX_VALUE : (now - lastRebuildPublishMs);

		final int decisionMin = 1;

		ChurnSnapshot churnSnapshot = churnSampler.snapshot();
		double churnRatio = churnSnapshot.sampled < decisionMin
				? 0.0
				: Math.max(churnSnapshot.readdRatio(), churnSnapshot.removalRatio());

		double score = clamp(churnRatio, 0.0, 1.0);

		return new Staleness(
				age,
				lastRebuildPublishMs,
				churnSnapshot.sampled,
				churnSnapshot.removed,
				churnSnapshot.readded,
				churnSnapshot.removalRatio(),
				churnSnapshot.readdRatio(),
				score);
	}

	/** Convenience: true if combined staleness score exceeds a given threshold. */
	public boolean isStale(double threshold) {
		Staleness staleness = staleness();
		int decisionMin = 1;
		boolean removalBreach = staleness.sampledAdds >= decisionMin
				&& staleness.sampledRemovalRatio >= churnRemovalRatioThreshold;
		boolean readdBreach = staleness.sampledAdds >= decisionMin
				&& staleness.sampledReaddRatio >= churnReaddThreshold;
		return removalBreach || readdBreach || staleness.stalenessScore > threshold;
	}

	// ──────────────────────────────────────────────────────────────
	// Staleness helpers (private)
	// ──────────────────────────────────────────────────────────────

	private static double clamp(double v, double lo, double hi) {
		return Math.max(lo, Math.min(hi, v));
	}

	/**
	 * Determine how frequently churn events should be sampled, expressed as "every N statements".
	 * <p>
	 * Rules:
	 * <ul>
	 * <li>When both {@code churnSamplePercent} and {@code churnSampleMin} are zero or negative, sampling is
	 * disabled.</li>
	 * <li>Base interval is derived from {@code churnSamplePercent * approxStoreSize} (rounded to ≥ 1) when percent &gt;
	 * 0.</li>
	 * <li>The interval is never smaller (more frequent) than {@code churnSampleMin} when
	 * {@code churnSampleMin &gt; 0}.</li>
	 * <li>If {@code churnSampleMax &gt; 0} and the calculated interval is below it, the interval is raised to
	 * {@code churnSampleMax} to avoid oversampling.</li>
	 * </ul>
	 */
	private long samplingInterval() {
		if (churnSamplePercent <= 0.0 && churnSampleMin <= 0) {
			return 0L; // sampling disabled
		}

		long interval = 0L;

		if (churnSamplePercent > 0.0) {
			double raw = approxStoreSize.get() * churnSamplePercent;
			long pctInterval = Math.max(1L, Math.round(raw));
			interval = Math.max(interval, pctInterval);
		}

		if (churnSampleMin > 0) {
			interval = Math.max(interval, churnSampleMin);
		}

		if (churnSampleMax > 0 && interval > 0 && interval < churnSampleMax) {
			interval = churnSampleMax;
		}

		return interval;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Persistence public API */
	/* ────────────────────────────────────────────────────────────── */

	/**
	 * Best-effort snapshot persistence intended for scheduled store-level sync/commit paths.
	 *
	 * @return true if a snapshot was written.
	 */
	public boolean persistIfDirty() {
		if (!persistenceEnabled || persistenceFile == null) {
			return false;
		}
		if (!dirty.get() || !sketchesLoaded) {
			return false;
		}
		synchronized (persistLock) {
			if (!dirty.get() || !sketchesLoaded) {
				return false;
			}
			try {
				writeSnapshot(persistenceFile);
				dirty.set(false);
				return true;
			} catch (Throwable t) {
				logger.warn("Failed to persist join estimator snapshot to {}", persistenceFile, t);
				return false;
			}
		}
	}

	/**
	 * Release in-memory sketches. Query planning falls back until sketches are lazy-loaded or rebuilt.
	 */
	public void unload() {
		unloadInternal(false);
	}

	private void unloadInternal(boolean markRebuildRequired) {
		synchronized (bufA) {
			bufA.clear();
		}
		synchronized (bufB) {
			bufB.clear();
		}
		seenTriples = 0L;
		sketchesLoaded = false;
		if (markRebuildRequired) {
			rebuildRequired.set(true);
		}
	}

	private boolean tryLoadFromDisk() {
		if (!persistenceEnabled || persistenceFile == null) {
			return false;
		}
		if (isLowMemory()) {
			return false;
		}
		synchronized (loadLock) {
			if (sketchesLoaded) {
				return true;
			}
			if (!Files.isReadable(persistenceFile)) {
				return false;
			}
			try {
				readSnapshot(persistenceFile);
				sketchesLoaded = true;
				rebuildRequired.set(false);
				dirty.set(false);
				return true;
			} catch (Throwable t) {
				logger.warn("Failed to load join estimator snapshot from {}", persistenceFile, t);
				return false;
			}
		}
	}

	private boolean isLowMemory() {
		BooleanSupplier supplier = lowMemorySupplier;
		if (supplier != null) {
			try {
				return supplier.getAsBoolean();
			} catch (Throwable t) {
				logger.debug("Ignoring low-memory supplier failure", t);
			}
		}
		return isMemoryLowHeuristic();
	}

	private static boolean isMemoryLowHeuristic() {
		Runtime rt = Runtime.getRuntime();
		long max = rt.maxMemory();
		long total = rt.totalMemory();
		long free = rt.freeMemory();
		long used = total - free;
		long freeToAllocate = max - used;

		final long absMin = 64L * 1024L * 1024L;
		final double ratioMin = 1.0 / 8.0;
		return freeToAllocate < absMin || (freeToAllocate + 0.0) / (max + 0.0) < ratioMin;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Snapshot IO */
	/* ────────────────────────────────────────────────────────────── */

	private void writeSnapshot(Path file) throws IOException {
		State snap = current;
		synchronized (snap) {
			Path parent = file.getParent();
			if (parent != null) {
				Files.createDirectories(parent);
			}

			Path tmp = file.resolveSibling(file.getFileName().toString() + ".tmp");
			try (OutputStream raw = new BufferedOutputStream(
					Files.newOutputStream(tmp, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING))) {
				raw.write(PERSIST_MAGIC);
				raw.write(PERSIST_VERSION);
				raw.flush();

				try (DataOutputStream out = new DataOutputStream(new GZIPOutputStream(raw))) {
					out.writeInt(snap.buckets);
					out.writeInt(snap.k);
					writeString(out, defaultContextString);
					out.writeLong(seenTriples);
					out.writeLong(approxStoreSize.get());
					out.writeLong(lastRebuildPublishMs);
					writeState(out, snap);
					out.writeByte(REC_EOF);
				}
			}

			try {
				Files.move(tmp, file, StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.ATOMIC_MOVE);
			} catch (IOException e) {
				Files.move(tmp, file, StandardCopyOption.REPLACE_EXISTING);
			}
		}
	}

	private void readSnapshot(Path file) throws IOException {
		try (InputStream raw = new BufferedInputStream(Files.newInputStream(file))) {
			byte[] magic = new byte[PERSIST_MAGIC.length];
			int read = raw.read(magic);
			if (read != PERSIST_MAGIC.length) {
				throw new EOFException("Short read of estimator snapshot header");
			}
			for (int i = 0; i < PERSIST_MAGIC.length; i++) {
				if (magic[i] != PERSIST_MAGIC[i]) {
					throw new IOException("Not a join estimator snapshot file");
				}
			}

			int version = raw.read();
			if (version != PERSIST_VERSION) {
				throw new IOException("Unsupported join estimator snapshot version: " + version);
			}

			try (DataInputStream in = new DataInputStream(new GZIPInputStream(raw))) {
				int buckets = in.readInt();
				int k = in.readInt();
				String defCtx = readString(in);
				long seen = in.readLong();
				long approx = in.readLong();
				long lastPublish = in.readLong();

				if (buckets != this.nominalEntries) {
					throw new IOException(
							"Snapshot buckets mismatch: snapshot=" + buckets + " current=" + this.nominalEntries);
				}
				if (k != this.bufA.k) {
					throw new IOException("Snapshot sketchK mismatch: snapshot=" + k + " current=" + this.bufA.k);
				}
				if (!Objects.equals(defCtx, this.defaultContextString)) {
					throw new IOException("Snapshot defaultContextString mismatch");
				}

				synchronized (bufA) {
					bufA.clear();
					synchronized (bufB) {
						bufB.clear();
						readStateInto(in, bufA, bufB);
					}
				}

				current = bufA;
				usingA = true;
				seenTriples = seen;
				approxStoreSize.set(approx);
				lastRebuildPublishMs = lastPublish;
				churnSampler.reset();
			}
		}
	}

	private static void writeString(DataOutputStream out, String value) throws IOException {
		byte[] bytes = value.getBytes(StandardCharsets.UTF_8);
		out.writeInt(bytes.length);
		out.write(bytes);
	}

	private static String readString(DataInputStream in) throws IOException {
		int len = in.readInt();
		if (len < 0 || len > MAX_STRING_BYTES) {
			throw new IOException("Invalid string length: " + len);
		}
		byte[] bytes = new byte[len];
		in.readFully(bytes);
		return new String(bytes, StandardCharsets.UTF_8);
	}

	private static void writeSketch(DataOutputStream out, UpdateSketch sketch) throws IOException {
		int retained = sketch.getRetainedEntries();
		out.writeInt(retained);
		HashIterator it = sketch.iterator();
		int written = 0;
		while (it.next()) {
			out.writeLong(it.get());
			written++;
		}
		if (written != retained) {
			throw new IOException("Sketch retained-entry count changed while serializing");
		}
	}

	private static UpdateSketch readSketch(DataInputStream in, int k) throws IOException {
		int retained = in.readInt();
		if (retained < 0 || retained > MAX_SKETCH_ENTRIES) {
			throw new IOException("Invalid retained entry count: " + retained);
		}
		UpdateSketch sketch = newSk(k);
		for (int i = 0; i < retained; i++) {
			sketch.update(in.readLong());
		}
		return sketch;
	}

	private static UpdateSketch cloneSketch(UpdateSketch source, int k) {
		UpdateSketch copy = newSk(k);
		HashIterator it = source.iterator();
		while (it.next()) {
			copy.update(it.get());
		}
		return copy;
	}

	private static void writeState(DataOutputStream out, State state) throws IOException {
		for (Component c : Component.values()) {
			writeSketchArray(out, REC_SINGLE_TRIPLE, false, (byte) c.ordinal(), state.singleTriples.get(c));
			writeSketchArray(out, REC_SINGLE_TRIPLE, true, (byte) c.ordinal(), state.delSingleTriples.get(c));
		}

		for (Component fixed : Component.values()) {
			SingleBuild add = state.singles.get(fixed);
			SingleBuild del = state.delSingles.get(fixed);
			for (Map.Entry<Component, AtomicReferenceArray<UpdateSketch>> entry : add.cmpl.entrySet()) {
				writeSketchArray(out, REC_SINGLE_CPL, false, (byte) fixed.ordinal(), (byte) entry.getKey().ordinal(),
						entry.getValue());
			}
			for (Map.Entry<Component, AtomicReferenceArray<UpdateSketch>> entry : del.cmpl.entrySet()) {
				writeSketchArray(out, REC_SINGLE_CPL, true, (byte) fixed.ordinal(), (byte) entry.getKey().ordinal(),
						entry.getValue());
			}
		}

		for (Pair pair : Pair.values()) {
			writePairBuild(out, pair, false, state.pairs.get(pair));
			writePairBuild(out, pair, true, state.delPairs.get(pair));
		}
	}

	private static void writeSketchArray(DataOutputStream out, byte recType, boolean isDelete, byte comp,
			AtomicReferenceArray<UpdateSketch> array) throws IOException {
		if (array == null) {
			return;
		}
		for (int i = 0; i < array.length(); i++) {
			UpdateSketch sketch = array.get(i);
			if (sketch == null || sketch.getRetainedEntries() == 0) {
				continue;
			}
			out.writeByte(recType);
			out.writeBoolean(isDelete);
			out.writeByte(comp);
			out.writeInt(i);
			writeSketch(out, sketch);
		}
	}

	private static void writeSketchArray(DataOutputStream out, byte recType, boolean isDelete, byte fixed, byte other,
			AtomicReferenceArray<UpdateSketch> array) throws IOException {
		if (array == null) {
			return;
		}
		for (int i = 0; i < array.length(); i++) {
			UpdateSketch sketch = array.get(i);
			if (sketch == null || sketch.getRetainedEntries() == 0) {
				continue;
			}
			out.writeByte(recType);
			out.writeBoolean(isDelete);
			out.writeByte(fixed);
			out.writeByte(other);
			out.writeInt(i);
			writeSketch(out, sketch);
		}
	}

	private static void writePairBuild(DataOutputStream out, Pair pair, boolean isDelete, PairBuild build)
			throws IOException {
		if (build == null) {
			return;
		}
		for (int x = 0; x < build.buckets; x++) {
			PairBuild.Row row = build.rows.get(x);
			if (row == null) {
				continue;
			}
			writePairRow(out, pair, isDelete, REC_PAIR_TRIPLE, row.triples, x);
			writePairRow(out, pair, isDelete, REC_PAIR_COMP1, row.comp1, x);
			writePairRow(out, pair, isDelete, REC_PAIR_COMP2, row.comp2, x);
		}
	}

	private static void writePairRow(DataOutputStream out, Pair pair, boolean isDelete, byte recType,
			AtomicReferenceArray<UpdateSketch> array, int x) throws IOException {
		for (int y = 0; y < array.length(); y++) {
			UpdateSketch sketch = array.get(y);
			if (sketch == null || sketch.getRetainedEntries() == 0) {
				continue;
			}
			out.writeByte(recType);
			out.writeBoolean(isDelete);
			out.writeByte((byte) pair.ordinal());
			out.writeInt(x);
			out.writeInt(y);
			writeSketch(out, sketch);
		}
	}

	private static void readStateInto(DataInputStream in, State stateA, State stateB) throws IOException {
		while (true) {
			byte rec = in.readByte();
			if (rec == REC_EOF) {
				return;
			}

			switch (rec) {
			case REC_SINGLE_TRIPLE: {
				boolean isDelete = in.readBoolean();
				Component component = Component.values()[in.readByte()];
				int idx = in.readInt();
				UpdateSketch skA = readSketch(in, stateA.k);
				UpdateSketch skB = cloneSketch(skA, stateB.k);

				AtomicReferenceArray<UpdateSketch> arrA = isDelete ? stateA.delSingleTriples.get(component)
						: stateA.singleTriples.get(component);
				AtomicReferenceArray<UpdateSketch> arrB = isDelete ? stateB.delSingleTriples.get(component)
						: stateB.singleTriples.get(component);
				arrA.set(idx, skA);
				arrB.set(idx, skB);
				break;
			}
			case REC_SINGLE_CPL: {
				boolean isDelete = in.readBoolean();
				Component fixed = Component.values()[in.readByte()];
				Component other = Component.values()[in.readByte()];
				int idx = in.readInt();
				UpdateSketch skA = readSketch(in, stateA.k);
				UpdateSketch skB = cloneSketch(skA, stateB.k);

				SingleBuild sbA = isDelete ? stateA.delSingles.get(fixed) : stateA.singles.get(fixed);
				SingleBuild sbB = isDelete ? stateB.delSingles.get(fixed) : stateB.singles.get(fixed);
				sbA.cmpl.get(other).set(idx, skA);
				sbB.cmpl.get(other).set(idx, skB);
				break;
			}
			case REC_PAIR_TRIPLE:
			case REC_PAIR_COMP1:
			case REC_PAIR_COMP2: {
				boolean isDelete = in.readBoolean();
				Pair pair = Pair.values()[in.readByte()];
				int x = in.readInt();
				int y = in.readInt();
				UpdateSketch skA = readSketch(in, stateA.k);
				UpdateSketch skB = cloneSketch(skA, stateB.k);

				PairBuild pbA = isDelete ? stateA.delPairs.get(pair) : stateA.pairs.get(pair);
				PairBuild pbB = isDelete ? stateB.delPairs.get(pair) : stateB.pairs.get(pair);

				PairBuild.Row rowA = pbA.getOrCreateRow(x);
				PairBuild.Row rowB = pbB.getOrCreateRow(x);

				AtomicReferenceArray<UpdateSketch> arrA;
				AtomicReferenceArray<UpdateSketch> arrB;
				if (rec == REC_PAIR_TRIPLE) {
					arrA = rowA.triples;
					arrB = rowB.triples;
				} else if (rec == REC_PAIR_COMP1) {
					arrA = rowA.comp1;
					arrB = rowB.comp1;
				} else {
					arrA = rowA.comp2;
					arrB = rowB.comp2;
				}

				arrA.set(y, skA);
				arrB.set(y, skB);
				break;
			}
			default:
				throw new IOException("Unknown estimator snapshot record type: " + rec);
			}
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Array helpers (private) */
	/* ────────────────────────────────────────────────────────────── */

	private static void clearArray(AtomicReferenceArray<?> arr) {
		if (arr == null) {
			return;
		}
		for (int i = 0; i < arr.length(); i++) {
			arr.set(i, null);
		}
	}

	private static void updateCell(AtomicReferenceArray<UpdateSketch> arr, int idx, long value, int k) {
		UpdateSketch sk = arr.get(idx);
		if (sk == null) {
			sk = newSk(k);
			arr.set(idx, sk);
		}
		sk.update(value);
	}

